#include <iostream>
using namespace std;
int main() 
{
    int n;
    string a,b,c;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        int k;
        cin>>k;
        cin>>a;
        getline(cin,c,'?');
        cin>>b;
        if(a.size()==b.size())
        {
            cout<<k<<" "<<a<<" = "<<1000000*k<<" "<<b<<endl;
        }
        else
        {
            cout<<k<<" "<<a<<" = "<<1000*k<<" "<<b<<endl;
        }
    }
    return 0;
}
